tool_input.script:
export const meta = {
  name: 'qa-multilingual',
  description: 'QA workflow: semantic search for multilingual support question',
  phases: [
    { title: 'SemanticSearch', detail: 'Search knowledge files for multilingual/i18n content' },
    { title: 'ReadSections', detail: 'Read selected sections' },
    { title: 'GenerateAnswer', detail: 'Generate Japanese answer' }
  ]
}

phase('SemanticSearch')

const KNOWLEDGE_BASE = '/home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/knowledge'
const SCRIPTS_BASE = '/home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/scripts'

// Run semantic search
const searchResult = await agent(`
You are executing semantic search for a Nablarch knowledge base.

## Task
Search the knowledge index and find relevant sections for this query:
"メッセージやラベルを日本語と英語で切り替えたい。多言語化の方法を教えてほしい（目的: 実装したい）"

## Knowledge Base Location
${KNOWLEDGE_BASE}

## Instructions
1. Read the file ${KNOWLEDGE_BASE}/../docs/index.md (or similar index file if it exists) to understand available knowledge files
2. Run: ls ${KNOWLEDGE_BASE}/ to see all available knowledge files
3. Look for files related to: 多言語, i18n, internationalization, メッセージ, ラベル, language switching
4. For each potentially relevant file, read its table of contents or first section to assess relevance
5. Select the most relevant files and sections

## Search Strategy
- Primary keywords: 多言語, i18n, 国際化, メッセージ切り替え, 言語切り替え, locale
- Secondary keywords: メッセージ管理, ラベル, リソースバンドル
- Look for files with names containing: message, i18n, format, label

## Output Format (JSON)
Return a JSON object with:
{
  "selected_pages": [
    {"path": "<relative path from knowledge/>", "reason": "<why selected>"}
  ],
  "excluded_pages": [
    {"path": "<relative path from knowledge/>", "reason": "<why excluded>"}
  ],
  "selected_sections": [
    {"file": "<full path>", "section_id": "<sN>", "relevance": "<high|partial>", "reason": "<why selected>"}
  ],
  "excluded_sections": [
    {"file": "<full path>", "section_id": "<sN>", "reason": "<why excluded>"}
  ]
}

Read actual file contents to make accurate selections. Focus on finding sections about multilingual support, message format switching, locale-based message selection.
`, { label: 'semantic-search', phase: 'SemanticSearch', schema: {
  type: 'object',
  properties: {
    selected_pages: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          path: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['path', 'reason']
      }
    },
    excluded_pages: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          path: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['path', 'reason']
      }
    },
    selected_sections: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          file: { type: 'string' },
          section_id: { type: 'string' },
          relevance: { type: 'string', enum: ['high', 'partial'] },
          reason: { type: 'string' }
        },
        required: ['file', 'section_id', 'relevance', 'reason']
      }
    },
    excluded_sections: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          file: { type: 'string' },
          section_id: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['file', 'section_id', 'reason']
      }
    }
  },
  required: ['selected_pages', 'excluded_pages', 'selected_sections', 'excluded_sections']
}})

phase('ReadSections')

// Select up to 10 sections: high first, then partial
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high')
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial')
const sectionsToRead = [...highSections, ...partialSections].slice(0, 10)

const readSectionArgs = sectionsToRead.map(s => `"${s.file}:${s.section_id}"`).join(' ')

let sectionsContent = ''
let readSections = []

if (sectionsToRead.length > 0) {
  readSections = sectionsToRead.map(s => `${s.file}:${s.section_id}`)

  const readResult = await agent(`
Run the following bash command and return the complete output:

\`\`\`bash
bash ${SCRIPTS_BASE}/read-sections.sh ${readSectionArgs}
\`\`\`

Return the complete raw output of the command. Do not truncate or summarize.
`, { label: 'read-sections', phase: 'ReadSections' })

  sectionsContent = readResult
}

phase('GenerateAnswer')

// Generate answer
const answerResult = await agent(`
You are a Nablarch expert answering a user question in Japanese.

## User Question
メッセージやラベルを日本語と英語で切り替えたい。多言語化の方法を教えてほしい

## Purpose
実装したい

## Processing Type
null (cross-functional / not specific to one processing type)

## Section Contents
${sectionsContent || '(No sections found)'}

## Instructions
Generate a Japanese answer following this format:

**結論**: Direct answer (1-2 sentences, include specific method/class names)

**根拠**: Code examples, configuration examples, or spec information
- Show code/config in code blocks
- Quote code examples verbatim from sections

**注意点**: Constraints, common mistakes (omit if nothing applies)

参照: Only sections actually cited (file.json:sN format, omit category path)

Stay within 500 tokens (up to 800 for complex questions).
Do NOT infer claims not directly stated in sections. If information is missing, write "この情報は知識ファイルの対象範囲外です".

## Output Format (JSON)
{
  "answer_text": "<the full answer in Japanese markdown>",
  "used_sections": [
    {"ref": "<file.json:sN>", "reason": "<why used>"}
  ],
  "unused_sections": [
    {"ref": "<file.json:sN>", "reason": "<why not used>"}
  ],
  "nablarch_claims": [
    {"claim": "<specific Nablarch claim>", "supported_by": "<section_id or 'unsupported'>"}
  ]
}
`, { label: 'generate-answer', phase: 'GenerateAnswer', schema: {
  type: 'object',
  properties: {
    answer_text: { type: 'string' },
    used_sections: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          ref: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['ref', 'reason']
      }
    },
    unused_sections: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          ref: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['ref', 'reason']
      }
    },
    nablarch_claims: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          claim: { type: 'string' },
          supported_by: { type: 'string' }
        },
        required: ['claim', 'supported_by']
      }
    }
  },
  required: ['answer_text', 'used_sections', 'unused_sections', 'nablarch_claims']
}})

// Verify: check for unsupported claims
const unsupportedClaims = answerResult.nablarch_claims.filter(c => c.supported_by === 'unsupported')
let finalAnswer = answerResult.answer_text

if (unsupportedClaims.length > 0) {
  // Re-generate without unsupported claims
  const regenResult = await agent(`
You are a Nablarch expert answering a user question in Japanese.

## User Question
メッセージやラベルを日本語と英語で切り替えたい。多言語化の方法を教えてほしい

## Section Contents
${sectionsContent || '(No sections found)'}

## IMPORTANT CONSTRAINT
The following claims were found to be unsupported by the sections and MUST NOT be included:
${unsupportedClaims.map(c => `- ${c.claim}`).join('\n')}

## Instructions
Generate a Japanese answer WITHOUT the unsupported claims above. Only include information directly supported by the sections.

Format:
**結論**: Direct answer (1-2 sentences)
**根拠**: Code/config examples from sections (verbatim)
**注意点**: Constraints (omit if nothing applies)
参照: Cited sections (file.json:sN format)

Return just the answer text as a plain string.
`, { label: 'regenerate-answer', phase: 'GenerateAnswer' })

  finalAnswer = regenResult
}

return {
  searchResult,
  readSections,
  sectionsContent: sectionsContent.substring(0, 500) + '...',
  answerResult,
  finalAnswer,
  verifyResult: unsupportedClaims.length === 0 ? 'PASS' : 'FAIL',
  unsupportedClaims
}
